import { safeGet } from '../../../../core/utils/safe-get.js';
import type { SeriesIdToColorScale } from '../../../context/XYChartColorScales.context.js';
import type {
  BarMetadata,
  DotMetadata,
  LineMetadata,
  RectDatapointInternal,
  RectMetadata,
  XYChartSeriesWithDatapoints,
} from '../../../types/xy-chart-internals.js';
import type {
  AreaDatapoint,
  BarDatapoint,
  DotDatapoint,
  LineDatapoint,
} from '../../../types/xy-chart.js';
import { getColorFromScaleAndData } from '../../../utils/coloring/get-color-from-scale-and-data.js';
import { isRectSeries } from '../../../utils/type-guards.js';

export const getColor = (
  series: XYChartSeriesWithDatapoints,
  datapoint:
    | DotDatapoint
    | LineDatapoint
    | RectDatapointInternal
    | BarDatapoint
    | AreaDatapoint,
  metadata: DotMetadata | RectMetadata | LineMetadata | BarMetadata,
  colorScaleMap: SeriesIdToColorScale,
  colorOverride?: string,
) => {
  if (isRectSeries(series)) {
    const colorScale = safeGet(colorScaleMap, series.id);

    return typeof datapoint.value === 'string' ||
      typeof datapoint.value === 'number'
      ? getColorFromScaleAndData(colorScale, datapoint.value, colorOverride)
      : '';
  }

  return (metadata as DotMetadata | LineMetadata | BarMetadata).color.Default;
};
